// Process each auction with Surplus List
const items = $input.all();
const results = [];

for (const item of items) {
  const record = item.json;
  const fields = record.fields || {};

  // Verify Surplus List exists and Foreclosures is empty
  if (fields["Surplus List"] && fields["Surplus List"].length > 0 && 
      (!fields["Foreclosures"] || fields["Foreclosures"].length === 0)) {

    const timestamp = new Date().toISOString();
    const surplusList = fields["Surplus List"];
    const attachment = surplusList[0]; // Get the first attachment

    // Extract binary data
    let pdfBinary = null;
    const binaryKeys = Object.keys(item.binary || {});

    // Look through binary data for the PDF
    for (const key of binaryKeys) {
      // If we find a PDF file that matches our attachment filename
      if (item.binary[key] && 
          item.binary[key].fileName === attachment.filename && 
          item.binary[key].mimeType === 'application/pdf') {
        pdfBinary = item.binary[key];
        break;
      }
    }

    results.push({
      json: {
        recordId: record.id,
        auctionName: fields["Auction Name"] || "Unknown Auction",
        county: fields["County"] ? fields["County"][0] : "Unknown County",
        surplusList: surplusList,
        attachment: attachment,
        message: `Surplus List found for auction at ${timestamp}`,
        action: 'process_surplus_list'
      },
      binary: pdfBinary ? { pdf: pdfBinary } : undefined
    });
  }
}

return results.length > 0 ? results : [{ json: { message: "No auctions found with surplus lists" } }];

// Get the PDF text content
const pdfText = $input.item.json.text || '';

// Create regular expressions for the data we want to extract
const parcelRegex = /Parcel(?:ID|\s#|\sNumber)?:?\s*([A-Z0-9-]+)/i;
const addressRegex = /(\d+\s+[^,\n]+(?:[,\s]+[^,\n]+){1,3})/i;
const ownerRegex = /Owner(?:'s)?\s*Name:?\s*([^\n]+)/i;
const amountRegex = /\$\s*(\d{1,3}(?:,\d{3})*\.?\d*)/;

// Function to extract data using regex
function extractWithRegex(text, regex) {
  const match = text.match(regex);
  return match ? match[1].trim() : null;
}

// Process each page of text
const lines = pdfText.split('\n');
const foreclosures = [];
let currentForeclosure = {};

for (const line of lines) {
  // Check for a parcel ID - usually indicates a new property
  const parcelMatch = line.match(parcelRegex);
  if (parcelMatch) {
    // If we have data for the previous property, save it
    if (currentForeclosure.parcelId) {
      foreclosures.push({...currentForeclosure});
    }

    // Start a new property
    currentForeclosure = {
      parcelId: parcelMatch[1].trim(),
      auctionId: $input.item.json.recordId,
      auctionName: $input.item.json.auctionName,
      county: $input.item.json.county
    };
  }

  // Extract other details
  if (!currentForeclosure.address) {
    const addressMatch = line.match(addressRegex);
    if (addressMatch) {
      currentForeclosure.address = addressMatch[1].trim();
    }
  }

  if (!currentForeclosure.owner) {
    const ownerMatch = line.match(ownerRegex);
    if (ownerMatch) {
      currentForeclosure.owner = ownerMatch[1].trim();
    }
  }

  if (!currentForeclosure.amount) {
    const amountMatch = line.match(amountRegex);
    if (amountMatch) {
      currentForeclosure.amount = amountMatch[1].trim();
    }
  }
}

// Don't forget the last property
if (currentForeclosure.parcelId) {
  foreclosures.push({...currentForeclosure});
}

// Return all foreclosures found
return {
  json: {
    auctionId: $input.item.json.recordId,
    auctionName: $input.item.json.auctionName,
    county: $input.item.json.county,
    foreclosuresCount: foreclosures.length,
    foreclosures: foreclosures
  }
};
